void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec3 txr = vec3(vUv,q2);
txr-=roam_sin.zyx*roam_cos.ywx;
    vec2 uv_echo = (vUv - 0.5)*vec2(-1,1) + 0.5;
    ret = mix( texture(sampler_main, (vUv-0.5)*0.98 + 0.5).xyz,
                texture(sampler_main, (uv_echo-0.5)*0.98 + 0.5).xyz,
                0.50
              )  + GetBlur3(vUv) + GetBlur3(uv_echo)
              + GetBlur1(vUv) + GetBlur1(uv_echo); //video echo; //video echo
    ret *= texture3D(sampler_noisevol_hq, txr);
   ret *= 2.0; //gamma
    //ret =  ret*(1 - ret)*10; //brighten

  fragColor = ret;
}
